import{_ as a,c as r,o as t,a1 as o}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"z.ai 集成: 能力边界详解 | Antigravity-Manager","description":"掌握 Antigravity Tools 的 z.ai 集成边界。了解请求路由、dispatch_mode 分流、模型映射、Header 安全策略，以及 MCP 反代与限制，避免误判。","frontmatter":{"title":"z.ai 集成: 能力边界详解 | Antigravity-Manager","sidebarTitle":"z.ai 边界速查","subtitle":"z.ai 集成: 能力边界详解","description":"掌握 Antigravity Tools 的 z.ai 集成边界。了解请求路由、dispatch_mode 分流、模型映射、Header 安全策略，以及 MCP 反代与限制，避免误判。","tags":["z.ai","MCP","Claude","能力边界"],"prerequisite":["start-getting-started","platforms-mcp"],"order":3},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}'),i={name:"zh/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function d(c,e,l,s,n,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="z-ai-集成的能力边界-已实现-vs-明确未实现" tabindex="-1">z.ai 集成的能力边界（已实现 vs 明确未实现） <a class="header-anchor" href="#z-ai-集成的能力边界-已实现-vs-明确未实现" aria-label="Permalink to &quot;z.ai 集成的能力边界（已实现 vs 明确未实现）&quot;">​</a></h1><p>这篇文档只讲 Antigravity Tools 的 z.ai“边界”，不讲“怎么接”。如果你发现某个能力没生效，先来这里对照一下：它到底是没开、没配，还是压根就没实现。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>判断一件事该不该指望 z.ai：哪些是“已实现”，哪些是“文档明确没做”</li><li>搞清 z.ai 只影响哪些端点（以及哪些端点完全不受影响）</li><li>看到每个结论的源码/文档证据（带 GitHub 行号链接），方便你自己复核</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能已经在 Antigravity Tools 里打开了 z.ai，但一用就遇到这些疑惑：</p><ul><li>为什么有些请求会走 z.ai，有些完全不走？</li><li>MCP 端点能不能当成“完整 MCP Server”？</li><li>UI 里看得到的开关，到底有没有对应到真实实现？</li></ul><h2 id="什么是-z-ai-集成-在本项目里" tabindex="-1">什么是 z.ai 集成（在本项目里）？ <a class="header-anchor" href="#什么是-z-ai-集成-在本项目里" aria-label="Permalink to &quot;什么是 z.ai 集成（在本项目里）？&quot;">​</a></h2><p><strong>z.ai 集成</strong>在 Antigravity Tools 里是一个可选的“上游 provider + MCP 扩展”。它只在特定条件下接管 Claude 协议请求，并提供 MCP Search/Reader 反代与一个最小化的 Vision MCP 内置服务器；它不是全协议、全能力的替换方案。</p><div class="info custom-block"><p class="custom-block-title">一句话记忆</p><p>你可以把 z.ai 当成“Claude 请求的可选上游 + 一组可开关的 MCP 端点”，别把它当成“把 z.ai 的所有能力完整搬进来”。</p></div><h2 id="已实现-稳定可用-以源码为准" tabindex="-1">已实现：稳定可用（以源码为准） <a class="header-anchor" href="#已实现-稳定可用-以源码为准" aria-label="Permalink to &quot;已实现：稳定可用（以源码为准）&quot;">​</a></h2><h3 id="_1-仅-claude-协议会走-z-ai-v1-messages-v1-messages-count-tokens" tabindex="-1">1) 仅 Claude 协议会走 z.ai（/v1/messages + /v1/messages/count_tokens） <a class="header-anchor" href="#_1-仅-claude-协议会走-z-ai-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) 仅 Claude 协议会走 z.ai（/v1/messages + /v1/messages/count_tokens）&quot;">​</a></h3><p>z.ai 的 Anthropic 上游转发只在 Claude handler 的 z.ai 分支发生：</p><ul><li><code>POST /v1/messages</code>：当 <code>use_zai=true</code> 时调用 <code>forward_anthropic_json(...)</code> 把 JSON 请求转发到 z.ai Anthropic 兼容端点</li><li><code>POST /v1/messages/count_tokens</code>：当 z.ai 启用时同样转发；否则返回占位的 <code>{input_tokens:0, output_tokens:0}</code></li></ul><p>证据：</p><ul><li>z.ai 分支选择与转发入口：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>count_tokens 的 z.ai 分支与占位返回：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>z.ai Anthropic 转发实现：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">“响应流式”怎么理解？</p><p><code>forward_anthropic_json</code> 会把上游响应体以 <code>bytes_stream()</code> 流式回传给客户端，不解析 SSE（见 <code>providers/zai_anthropic.rs</code> 的 Response body 构建）。</p></div><h3 id="_2-调度模式-dispatch-mode-的-真实含义" tabindex="-1">2) 调度模式（dispatch_mode）的“真实含义” <a class="header-anchor" href="#_2-调度模式-dispatch-mode-的-真实含义" aria-label="Permalink to &quot;2) 调度模式（dispatch_mode）的“真实含义”&quot;">​</a></h3><p><code>dispatch_mode</code> 决定 <code>/v1/messages</code> 是否走 z.ai：</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>会发生什么</th><th>证据</th></tr></thead><tbody><tr><td><code>off</code></td><td>永不使用 z.ai</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>所有 Claude 请求都走 z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Google 池不可用（0 账号或“没有可用账号”）才走 z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>把 z.ai 当作“额外 1 个槽位”参与轮询（不保证一定命中）</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">pooled 的常见误解</p><p><code>pooled</code> 不是“z.ai + Google 账号池都用，而且按权重稳定分流”。代码里明确写了“no strict guarantees”，本质是一个轮询槽位（<code>slot == 0</code> 才走 z.ai）。</p></div><h3 id="_3-模型映射-claude-模型名怎么变成-z-ai-的-glm" tabindex="-1">3) 模型映射：Claude 模型名怎么变成 z.ai 的 glm-*？ <a class="header-anchor" href="#_3-模型映射-claude-模型名怎么变成-z-ai-的-glm" aria-label="Permalink to &quot;3) 模型映射：Claude 模型名怎么变成 z.ai 的 glm-*？&quot;">​</a></h3><p>在转发到 z.ai 之前，如果请求体里有 <code>model</code> 字段，会被重写：</p><ol><li><code>proxy.zai.model_mapping</code> 精确匹配（同时支持原串和 lower-case key）</li><li><code>zai:&lt;model&gt;</code> 前缀：去掉 <code>zai:</code> 直接用</li><li><code>glm-*</code>：保持不变</li><li>非 <code>claude-*</code>：保持不变</li><li><code>claude-*</code> 且包含 <code>opus/haiku</code>：映射到 <code>proxy.zai.models.opus/haiku</code>；否则默认 <code>sonnet</code></li></ol><p>证据：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-转发时的-header-安全策略-避免泄露本地-proxy-key" tabindex="-1">4) 转发时的 Header 安全策略（避免泄露本地 proxy key） <a class="header-anchor" href="#_4-转发时的-header-安全策略-避免泄露本地-proxy-key" aria-label="Permalink to &quot;4) 转发时的 Header 安全策略（避免泄露本地 proxy key）&quot;">​</a></h3><p>z.ai 上游转发不会“原样带所有 Header”，而是做了两层防线：</p><ul><li>只放行一小部分 Header（例如 <code>content-type</code>、<code>accept</code>、<code>anthropic-version</code>、<code>user-agent</code>）</li><li>把 z.ai 的 API Key 注入到上游（优先保持客户端用的鉴权方式：<code>x-api-key</code> 或 <code>Authorization: Bearer ...</code>）</li></ul><p>证据：</p><ul><li>Header 白名单：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>注入 z.ai auth：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="已实现-mcp-search-reader-反代-vision-内置" tabindex="-1">已实现：MCP（Search/Reader 反代 + Vision 内置） <a class="header-anchor" href="#已实现-mcp-search-reader-反代-vision-内置" aria-label="Permalink to &quot;已实现：MCP（Search/Reader 反代 + Vision 内置）&quot;">​</a></h2><h3 id="_1-mcp-search-reader-反向代理到-z-ai-的-mcp-端点" tabindex="-1">1) MCP Search/Reader：反向代理到 z.ai 的 MCP 端点 <a class="header-anchor" href="#_1-mcp-search-reader-反向代理到-z-ai-的-mcp-端点" aria-label="Permalink to &quot;1) MCP Search/Reader：反向代理到 z.ai 的 MCP 端点&quot;">​</a></h3><p>本地端点与上游地址是写死的：</p><table tabindex="0"><thead><tr><th>本地端点</th><th>上游地址</th><th>开关</th><th>证据</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404 不是“网络问题”</p><p>只要 <code>proxy.zai.mcp.enabled=false</code>，或者对应 <code>web_search_enabled/web_reader_enabled=false</code>，这些端点就会直接返回 404。</p></div><p>证据：</p><ul><li>MCP 总开关与 z.ai key 校验：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>路由注册：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-一个-最小化-streamable-http-mcp-内置服务器" tabindex="-1">2) Vision MCP：一个“最小化 Streamable HTTP MCP”内置服务器 <a class="header-anchor" href="#_2-vision-mcp-一个-最小化-streamable-http-mcp-内置服务器" aria-label="Permalink to &quot;2) Vision MCP：一个“最小化 Streamable HTTP MCP”内置服务器&quot;">​</a></h3><p>Vision MCP 不是反代，它是本地内置实现：</p><ul><li>端点：<code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> 支持：<code>initialize</code>、<code>tools/list</code>、<code>tools/call</code></li><li><code>GET</code> 返回 SSE keepalive（要求已初始化的 session）</li><li><code>DELETE</code> 结束 session</li></ul><p>证据：</p><ul><li>handler 主入口与方法分发：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li><code>initialize</code>、<code>tools/list</code>、<code>tools/call</code> 的实现：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Vision MCP 的“最小实现”定位：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-vision-mcp-工具集-8-个-与文件大小限制" tabindex="-1">3) Vision MCP 工具集（8 个）与文件大小限制 <a class="header-anchor" href="#_3-vision-mcp-工具集-8-个-与文件大小限制" aria-label="Permalink to &quot;3) Vision MCP 工具集（8 个）与文件大小限制&quot;">​</a></h3><p>工具列表来自 <code>tool_specs()</code>：</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>证据：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>本地文件会被读出来并编码成 <code>data:&lt;mime&gt;;base64,...</code>，同时有硬限制：</p><ul><li>图片上限 5 MB（<code>image_source_to_content(..., 5)</code>）</li><li>视频上限 8 MB（<code>video_source_to_content(..., 8)</code>）</li></ul><p>证据：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="明确未实现-不要期待-以文档声明与实现细节为准" tabindex="-1">明确未实现 / 不要期待（以文档声明与实现细节为准） <a class="header-anchor" href="#明确未实现-不要期待-以文档声明与实现细节为准" aria-label="Permalink to &quot;明确未实现 / 不要期待（以文档声明与实现细节为准）&quot;">​</a></h2><h3 id="_1-z-ai-用量-预算监控-usage-budget-未实现" tabindex="-1">1) z.ai 用量/预算监控（usage/budget）未实现 <a class="header-anchor" href="#_1-z-ai-用量-预算监控-usage-budget-未实现" aria-label="Permalink to &quot;1) z.ai 用量/预算监控（usage/budget）未实现&quot;">​</a></h3><p><code>docs/zai/implementation.md</code> 明确写了“not implemented yet”。这意味着：</p><ul><li>你不能指望 Antigravity Tools 提供 z.ai 的 usage/budget 查询或告警</li><li>配额治理（Quota Protection）也不会自动读 z.ai 的预算/用量数据</li></ul><p>证据：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp-不是完整-mcp-server" tabindex="-1">2) Vision MCP 不是完整 MCP Server <a class="header-anchor" href="#_2-vision-mcp-不是完整-mcp-server" aria-label="Permalink to &quot;2) Vision MCP 不是完整 MCP Server&quot;">​</a></h3><p>Vision MCP 目前定位就是“只够工具调用”的最小实现：prompts/resources、resumability、streamed tool output 等都还没做。</p><p>证据：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude-不会反映-z-ai-的真实模型列表" tabindex="-1">3) <code>/v1/models/claude</code> 不会反映 z.ai 的真实模型列表 <a class="header-anchor" href="#_3-v1-models-claude-不会反映-z-ai-的真实模型列表" aria-label="Permalink to &quot;3) `/v1/models/claude` 不会反映 z.ai 的真实模型列表&quot;">​</a></h3><p>这个端点返回的模型列表来自本地内置映射与自定义映射（<code>get_all_dynamic_models</code>），不会去请求 z.ai 上游的 <code>/v1/models</code>。</p><p>证据：</p><ul><li>handler：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>列表生成逻辑：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="配置字段速查-z-ai-相关" tabindex="-1">配置字段速查（z.ai 相关） <a class="header-anchor" href="#配置字段速查-z-ai-相关" aria-label="Permalink to &quot;配置字段速查（z.ai 相关）&quot;">​</a></h2><p>z.ai 配置在 <code>ProxyConfig.zai</code> 下，包含这些字段：</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code>（<code>off/exclusive/pooled/fallback</code>）</li><li><code>model_mapping</code>（精确匹配覆盖）</li><li><code>models.{opus,sonnet,haiku}</code>（Claude 家族默认映射）</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>默认值（base_url / 默认模型）也在同一个文件里：</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><p>证据：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></p><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>z.ai 目前只会接管 Claude 协议（<code>/v1/messages</code> + <code>count_tokens</code>），其他协议端点不是“自动走 z.ai”</li><li>MCP Search/Reader 是反代；Vision MCP 是本地最小实现，不是完整 MCP Server</li><li><code>/v1/models/claude</code> 的模型列表来自本地映射，不代表 z.ai 上游真实模型</li></ul><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../changelog/release-notes/">版本演进</a></strong>。</p></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>z.ai 集成范围（Claude 协议 + MCP + Vision MCP）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L12-L17" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>12-17</td></tr><tr><td>z.ai 调度模式与模型默认值</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>20-116</td></tr><tr><td>z.ai 默认 base_url / 默认模型</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td><code>/v1/messages</code> 是否走 z.ai 的选择逻辑</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td><code>/v1/messages/count_tokens</code> 的 z.ai 转发与占位返回</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>1186-1209</td></tr><tr><td>z.ai Anthropic 上游转发（JSON 转发 + 响应流式回传）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>133-219</td></tr><tr><td>z.ai 模型映射规则（map_model_for_zai）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>Header 白名单 + 注入 z.ai auth</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>70-110</td></tr><tr><td>MCP Search/Reader 反代与开关</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L45-L157" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></td><td>45-157</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Vision MCP 最小实现定位（非完整 MCP Server）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></td><td>17-37</td></tr><tr><td>Vision 工具列表与限制（tool_specs + 文件大小 + stream=false）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td><code>/v1/models/claude</code> 模型列表来源（本地映射，不查上游）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>84-132</td></tr><tr><td>用量/预算监控未实现（文档声明）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>194-198</td></tr></tbody></table></details>',76)])])}const u=a(i,[["render",d]]);export{b as __pageData,u as default};
